from flask import Blueprint, jsonify
from ..services.guide_service import (
    get_all_sections, get_section_by_slug, get_navigation
)

guide_bp = Blueprint("guide", __name__, url_prefix="/api/guide")

@guide_bp.route("/sections")
def list_sections():
    sections = get_all_sections()
    summary = [
        {
            "id": s["id"], "title": s["title"], "slug": s["slug"],
            "description": s.get("description", ""),
            "icon": s.get("icon", ""),
            "order": s.get("order", 0),
            "estimatedMinutes": s.get("estimatedMinutes", 0),
            "difficulty": s.get("difficulty", "beginner"),
        }
        for s in sections
    ]
    return jsonify(summary)

@guide_bp.route("/sections/<slug>")
def get_section(slug):
    section = get_section_by_slug(slug)
    if section is None:
        return jsonify({"error": "Section not found"}), 404
    return jsonify(section)

@guide_bp.route("/navigation")
def navigation():
    return jsonify(get_navigation())

from flask import Blueprint, jsonify, request
from ..services.exam_service import (
    get_all_questions, get_random_questions,
    get_categories, filter_questions
)

exam_bp = Blueprint("exam", __name__, url_prefix="/api/exam")

@exam_bp.route("/questions")
def list_questions():
    category = request.args.get("category")
    difficulty = request.args.get("difficulty")
    if category or difficulty:
        questions = filter_questions(category=category, difficulty=difficulty)
    else:
        questions = get_all_questions()
    return jsonify(questions)

@exam_bp.route("/questions/random")
def random_questions():
    count = request.args.get("count", 30, type=int)
    return jsonify(get_random_questions(count))

@exam_bp.route("/categories")
def list_categories():
    return jsonify(get_categories())

from flask import Blueprint, jsonify, request
from ..services.glossary_service import (
    get_all_terms, get_categories, search_terms
)

glossary_bp = Blueprint("glossary", __name__, url_prefix="/api/glossary")

@glossary_bp.route("/terms")
def list_terms():
    category = request.args.get("category")
    if category:
        terms = [t for t in get_all_terms() if t.get("category") == category]
    else:
        terms = get_all_terms()
    return jsonify(terms)

@glossary_bp.route("/categories")
def list_categories():
    return jsonify(get_categories())

@glossary_bp.route("/search")
def search():
    query = request.args.get("q", "")
    if not query:
        return jsonify([])
    return jsonify(search_terms(query))
